local FEEDBACK_COOLDOWN, lastFeedback = 20, 0
local ERRMAP = {
    empty = "Tin nhắn đang trống.", no_links = "Không cho phép chèn link.",
    too_long = "Tin nhắn quá dài (tối đa 500 ký tự).", rate_limited = "Bạn đã đạt giới hạn 3 tin nhắn. Vui lòng thử lại sau.",
    busy = "Máy chủ đang bận. Vui lòng thử lại.", banned = "Bạn không được phép gửi góp ý.",
    discord_error = "Gửi thất bại. Vui lòng thử lại.", network = "Lỗi mạng.",
    no_request = "Executor của bạn không thể gửi yêu cầu.", bad_response = "Máy chủ trả về phản hồi không mong đợi.",
    unreachable = "Executor của bạn không thể kết nối máy chủ (lỗi TLS). Vui lòng thử executor khác.",
}
local FG = Tabs.Suggest:AddLeftGroupbox("Góp Ý / Trợ Giúp", "message-square")
FG:AddDropdown("FeedbackType", {Text = "Loại", Values = {"Suggestion", "Bug", "Help"}, Default = "Suggestion", Callback = function() end})
FG:AddInput("FeedbackMsg", {Default = "", Numeric = false, Finished = false, ClearTextOnFocus = false, Text = "Tin Nhắn", Placeholder = "Nhập tin nhắn của bạn (tối đa 500 ký tự, không link)"})
local fbStatus = FG:AddLabel("", true)
FG:AddButton({
    Text = "📨 Send",
    Func = function()
        local now = tick()
        if now - lastFeedback < FEEDBACK_COOLDOWN then
            safeSet(fbStatus, string.format("Vui lòng chờ %d giây trước khi gửi lại.", math.ceil(FEEDBACK_COOLDOWN - (now - lastFeedback))))
            return
        end
        local ftype = tostring((Options.FeedbackType and Options.FeedbackType.Value) or "Suggestion"):lower()
        local msg   = M.trim((Options.FeedbackMsg and Options.FeedbackMsg.Value) or "")
        if msg == "" then safeSet(fbStatus, "Tin nhắn đang trống."); return end
        if #msg > 500 then safeSet(fbStatus, "Tin nhắn quá dài (tối đa 500 ký tự)."); return end
        local low = msg:lower()
        if low:find("http", 1, true) or low:find("discord.gg", 1, true) or low:find("www.", 1, true) or low:find(".gg/", 1, true) then
            safeSet(fbStatus, "Không cho phép chèn link."); return
        end
        safeSet(fbStatus, "Đang gửi...")
        task.spawn(function()
            local sok, err = M.sendFeedback(ftype, msg, (preCheck and preCheck.session_token) or "")
            if sok then
                lastFeedback = tick()
                safeSet(fbStatus, "✅ Đã gửi. Cảm ơn bạn!")
                pcall(function() Options.FeedbackMsg:SetValue("") end)
                Library:Notify({Title = "COMBOWICK", Description = "Góp ý của bạn đã được gửi. Cảm ơn bạn!", Time = 3})
            else
                safeSet(fbStatus, ERRMAP[err] or ("Gửi thất bại: " .. tostring(err)))
            end
        end)
    end,
})
