task.spawn(function()
    safeSet(statusLabel, "Đang xác thực...")

    local result = M.withRetry(M.checkSession, M.hwid)

    if result == nil then
        safeSet(statusLabel, "Trạng thái: Thất Bại")
        Library:Notify({Title="COMBOWICK", Description="Kiểm tra phiên thất bại.", Time=5})

    elseif result.status == "allowed" or result.status == "session_active" then
        if result.disabled then
            safeSet(statusLabel, "⛔ Game Bị Tắt")
            safeSet(hintLabel, "Bản miễn phí không khả dụng ở đây. Hãy lấy key.")
            Library:Notify({Title="COMBOWICK", Description="Bản miễn phí bị tắt cho game này. Vui lòng dùng key.", Time=6})
            return
        end
        local token = result.session_token
        if type(token) ~= "string" or #token < 20 then
            safeSet(statusLabel, "Trạng thái: Thất Bại")
        else
            safeSet(statusLabel, "Trạng thái: Đã Xác Thực")
            Library:Notify({Title="COMBOWICK", Description="Bạn đã được xác thực.", Time=3})
            _G.COMBOWICK_FREE   = true
            _G.COMBOWICK_ACTIVE = true
            local remaining = tonumber(result.remaining) or 0
            task.spawn(function()
                while remaining > 0 do
                    local fmt = M.formatTime(remaining)
                    safeSet(timerLabel, string.format("Thời gian còn lại: %s", fmt))
                    safeSet(lSession, string.format("Thời gian phiên: %s", fmt))
                    task.wait(1); remaining = remaining - 1
                end
                safeSet(timerLabel, "Phiên đã hết hạn.")
                safeSet(lSession, "Thời gian phiên: đã hết hạn")
                _G.COMBOWICK_ACTIVE = false
                pcall(function() Library:Unload() end)
                task.wait(0.5)
                M.reloadExist()
            end)
            local scriptUrl = M.getScriptForGame(token)
            if M.loadFreeScript(scriptUrl, token) then task.wait(2); pcall(function() Library:Unload() end) end
        end

    elseif result.status == "cooldown" then
        local remaining = tonumber(result.remaining) or 0
        safeSet(statusLabel, "Đang Trong Thời Gian Chờ")
        safeSet(hintLabel, "Lấy key 11 giờ, hoặc đợi hết thời gian chờ.")
        Library:Notify({Title="COMBOWICK", Description="Bạn đang trong thời gian chờ. Lấy key để bỏ qua chờ đợi.", Time=6})
        task.spawn(function()
            while remaining > 0 do
                local fmt = M.formatTime(remaining)
                safeSet(timerLabel, string.format("Thời gian chờ: %s", fmt))
                safeSet(lCooldown, string.format("Thời gian chờ: %s", fmt))
                task.wait(1); remaining = remaining - 1
            end
            safeSet(timerLabel, "Thời gian chờ đã kết thúc.")
            safeSet(lCooldown, "Thời gian chờ: đã xong")
            safeSet(hintLabel, "")
            Library:Notify({Title="COMBOWICK", Description="Thời gian chờ đã kết thúc. Đang tải lại...", Time=3})
            pcall(function() Library:Unload() end)
            task.wait(0.5)
            M.reloadExist()
        end)

    elseif result.status == "throttled" then
        local remaining = tonumber(result.remaining) or 0
        safeSet(statusLabel, "Quá Nhiều Yêu Cầu")
        safeSet(hintLabel, "Quá nhiều yêu cầu. Vui lòng đợi.")
        Library:Notify({Title="COMBOWICK", Description="Quá nhiều yêu cầu. Vui lòng đợi một lát.", Time=5})
        task.spawn(function()
            while remaining > 0 do
                safeSet(timerLabel, string.format("Thử lại sau %s", M.formatTime(remaining)))
                task.wait(1); remaining = remaining - 1
            end
            safeSet(timerLabel, "Đang tải lại...")
            safeSet(hintLabel, "")
            pcall(function() Library:Unload() end)
            task.wait(0.5)
            M.reloadExist()
        end)

    elseif result.status == "disabled" then
        safeSet(statusLabel, "Dịch Vụ Tạm Dừng")
        safeSet(hintLabel, "COMBOWICK đang tạm thời ngoại tuyến.")
        Library:Notify({Title="COMBOWICK", Description="Dịch vụ hiện đang bị tắt. Vui lòng thử lại sau.", Time=6})

    elseif result.status == "banned" then
        safeSet(statusLabel, "Bị Cấm")
        Library:Notify({Title="COMBOWICK", Description="Bạn đã bị cấm.", Time=5})

    elseif result.status == "game_not_allowed" then
        safeSet(statusLabel, "🚫 Game Không Được Hỗ Trợ")
        safeSet(hintLabel, "Game này chưa được hỗ trợ. Key premium vẫn dùng được nếu có script khả dụng.")
        Library:Notify({Title="COMBOWICK", Description="Game này chưa được hỗ trợ.", Time=6})

    else
        safeSet(statusLabel, "Lỗi")
        safeSet(hintLabel, "Không thể kết nối máy chủ. Vui lòng chạy lại script.")
        Library:Notify({Title="COMBOWICK", Description=tostring(result.message or "Đã xảy ra lỗi không xác định."), Time=5})
    end
end)

